# 73. bow_arrow 弓 + 箭
TEMPLATES.append({
    "name": "bow_arrow",
    "title": "弓 + 箭（弓身 + 弓弦 + 1 支箭）",
    "category": "weapon",
    "description": "弓身（Curve Bezier 弧形） + 弓弦（cylinder 细绳） + 1 支箭（cylinder + 头部 cone + 尾部 4 片 plane 当箭羽）。",
    "params": [
        {"name": "name",     "type": "string", "default": "Bow",     "description": "对象名"},
        {"name": "location", "type": "vec3",   "default": [0, 0, 1.0], "description": "中心位置"}
    ],
    "code": "import bpy, math\ntry:\n    _NAME = {{name|json}}\n    _LOC = {{location|json}}\n\n    wood_mat = bpy.data.materials.new(_NAME + '_wood')\n    wood_mat.use_nodes = True\n    b = wood_mat.node_tree.nodes.get('Principled BSDF')\n    if b and 'Base Color' in b.inputs:\n        b.inputs['Base Color'].default_value = (0.30, 0.18, 0.10, 1.0)\n    if b and 'Roughness' in b.inputs:\n        b.inputs['Roughness'].default_value = 0.6\n\n    string_mat = bpy.data.materials.new(_NAME + '_string')\n    string_mat.use_nodes = True\n    bs = string_mat.node_tree.nodes.get('Principled BSDF')\n    if bs and 'Base Color' in bs.inputs:\n        bs.inputs['Base Color'].default_value = (0.85, 0.82, 0.75, 1.0)\n\n    metal_mat = bpy.data.materials.new(_NAME + '_metal')\n    metal_mat.use_nodes = True\n    bm = metal_mat.node_tree.nodes.get('Principled BSDF')\n    if bm and 'Base Color' in bm.inputs:\n        bm.inputs['Base Color'].default_value = (0.7, 0.7, 0.72, 1.0)\n    if bm and 'Metallic' in bm.inputs:\n        bm.inputs['Metallic'].default_value = 0.9\n\n    # 弓身（贝塞尔曲线）\n    bpy.ops.curve.primitive_bezier_curve_add(location=_LOC)\n    bow = bpy.context.object; bow.name = _NAME + '_bow'\n    bow.data.bevel_depth = 0.012\n    bow.data.bevel_resolution = 4\n    bp = bow.data.splines[0].bezier_points\n    bp[0].co = (0, 0, -0.6)\n    bp[1].co = (0, 0, 0.6)\n    bp[0].handle_left = (0.3, 0, -0.9)\n    bp[0].handle_right = (0.3, 0, -0.3)\n    bp[1].handle_left = (0.3, 0, 0.3)\n    bp[1].handle_right = (0.3, 0, 0.9)\n    bow.data.materials.append(wood_mat)\n\n    # 弓弦（直线 cylinder）\n    bpy.ops.mesh.primitive_cylinder_add(radius=0.003, depth=1.2, vertices=6, location=_LOC)\n    string = bpy.context.object; string.name = _NAME + '_string'\n    string.data.materials.append(string_mat)\n\n    # 箭杆\n    arrow_y = -0.2\n    bpy.ops.mesh.primitive_cylinder_add(radius=0.008, depth=0.8, vertices=8, location=(_LOC[0] + 0.4, _LOC[1] + arrow_y, _LOC[2]))\n    shaft = bpy.context.object; shaft.name = _NAME + '_shaft'\n    shaft.rotation_euler = (0, math.radians(90), 0)\n    bpy.ops.object.transform_apply(location=False, rotation=True, scale=False)\n    shaft.data.materials.append(wood_mat)\n\n    # 箭头（cone）\n    bpy.ops.mesh.primitive_cone_add(radius1=0.018, radius2=0, depth=0.06, vertices=8, location=(_LOC[0] + 0.83, _LOC[1] + arrow_y, _LOC[2]))\n    tip = bpy.context.object; tip.name = _NAME + '_tip'\n    tip.rotation_euler = (0, math.radians(90), 0)\n    bpy.ops.object.transform_apply(location=False, rotation=True, scale=False)\n    tip.data.materials.append(metal_mat)\n\n    # 箭羽（3 片 plane）\n    feather_mat = bpy.data.materials.new(_NAME + '_feather')\n    feather_mat.use_nodes = True\n    bf = feather_mat.node_tree.nodes.get('Principled BSDF')\n    if bf and 'Base Color' in bf.inputs:\n        bf.inputs['Base Color'].default_value = (0.85, 0.20, 0.20, 1.0)\n    for i in range(3):\n        ang = i * math.pi * 2 / 3\n        bpy.ops.mesh.primitive_plane_add(size=0.08, location=(_LOC[0] - 0.05, _LOC[1] + arrow_y, _LOC[2]))\n        f = bpy.context.object; f.name = _NAME + '_feather_' + str(i + 1)\n        f.rotation_euler = (math.radians(90), 0, ang)\n        f.scale = (1.0, 0.6, 1.0)\n        bpy.ops.object.transform_apply(location=False, rotation=True, scale=True)\n        f.data.materials.append(feather_mat)\n    print('[apply_template] bow_arrow 完成')\nexcept Exception as _e:\n    import traceback; print('[apply_template] bow_arrow 失败:', _e); traceback.print_exc()\n"
})

